<?php
 namespace WPAICG\Vector\Providers\Qdrant\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Qdrant_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function list_indexes_logic(AIPKit_Vector_Qdrant_Strategy $strategyInstance, ?int $limit = null, ?string $order = null, ?string $after = null, ?string $before = null): array|WP_Error { $response = _request_logic($strategyInstance, 'GET', '/collections'); if (is_wp_error($response)) return $response; $collections_data = $response['collections'] ?? []; $formatted_collections = []; if (is_array($collections_data)) { foreach ($collections_data as $collection) { if (isset($collection['name'])) { $formatted_collections[] = [ 'id' => $collection['name'], 'name' => $collection['name'], ]; } } } return $formatted_collections; }